    `first_response_minutes` STRING COMMENT 'Minutes to first agent response.',
    `opened_at` TIMESTAMP COMMENT '',
    `priority` STRING COMMENT '',
    `reopen_count` STRING COMMENT 'Number of times the case was reopened.',
    `resolution_minutes` STRING COMMENT 'Minutes to full resolution.',
    `resolution_summary` STRING COMMENT 'Summary of the resolution provided.',
    `resolved_at` TIMESTAMP COMMENT '',
    `resolved_flag` BOOLEAN COMMENT '',
    `source_record_code` STRING COMMENT '',
    `support_case_status` STRING COMMENT 'Case status (open, pending, resolved, closed).',
    `subcategory` STRING COMMENT 'Issue subcategory.',
    `subject` STRING COMMENT 'Short subject/summary of the case.',
    `updated_at` TIMESTAMP COMMENT '',
    CONSTRAINT pk_support_case PRIMARY KEY(`support_case_id`)
) COMMENT 'Customer support / contact centre case.';

